import asyncio
import json
import logging
import signal
import uuid
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any, List

import websockets
from websockets.server import WebSocketServerProtocol

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")


@dataclass
class Item:
    id: str
    owner_id: str
    name: str
    quantity: int = 1
    tradable: bool = True


@dataclass
class Player:
    id: str
    name: str
    websocket: Optional[WebSocketServerProtocol] = None
    inventory: Set[str] = field(default_factory=set)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_locks: Dict[str, asyncio.Lock] = defaultdict(asyncio.Lock)
        self.connections: Dict[WebSocketServerProtocol, str] = {}
        self.global_lock = asyncio.Lock()

    async def send(self, ws: WebSocketServerProtocol, message: Dict[str, Any]) -> None:
        try:
            await ws.send(json.dumps(message))
        except Exception:
            logging.exception("Failed to send message")

    async def broadcast_to_players(self, player_ids: List[str], message: Dict[str, Any]) -> None:
        coros = []
        for pid in player_ids:
            player = self.players.get(pid)
            if player and player.websocket:
                coros.append(self.send(player.websocket, message))
        if coros:
            await asyncio.gather(*coros, return_exceptions=True)

    async def register_player(self, ws: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        player_id = data.get("player_id") or str(uuid.uuid4())
        name = data.get("name", f"Player-{player_id[:8]}")
        async with self.global_lock:
            player = self.players.get(player_id)
            if player is None:
                player = Player(id=player_id, name=name, websocket=ws)
                self.players[player_id] = player
                for i in range(3):
                    item_id = str(uuid.uuid4())
                    item = Item(
                        id=item_id,
                        owner_id=player_id,
                        name=f"StarterItem{i + 1}",
                        quantity=1,
                        tradable=True,
                    )
                    self.items[item_id] = item
                    player.inventory.add(item_id)
            else:
                player.websocket = ws
                player.name = name
            self.connections[ws] = player_id

        await self.send(
            ws,
            {
                "type": "registered",
                "player_id": player.id,
                "name": player.name,
                "inventory": await self.serialize_inventory(player.id),
            },
        )
        logging.info("Player registered: %s", player_id)

    async def unregister(self, ws: WebSocketServerProtocol) -> None:
        player_id = self.connections.pop(ws, None)
        if not player_id:
            return
        player = self.players.get(player_id)
        if player and player.websocket == ws:
            player.websocket = None
        logging.info("Player disconnected: %s", player_id)

    async def serialize_inventory(self, player_id: str) -> List[Dict[str, Any]]:
        player = self.players.get(player_id)
        if not player:
            return []
        result = []
        for item_id in list(player.inventory):
            item = self.items.get(item_id)
            if item:
                result.append(
                    {
                        "id": item.id,
                        "name": item.name,
                        "quantity": item.quantity,
                        "tradable": item.tradable,
                        "owner_id": item.owner_id,
                    }
                )
        return result

    async def handle_get_inventory(self, ws: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        player_id = self.connections.get(ws)
        if not player_id:
            await self.send(ws, {"type": "error", "message": "Not registered"})
            return
        inventory = await self.serialize_inventory(player_id)
        await self.send(ws, {"type": "inventory", "player_id": player_id, "items": inventory})

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int = 1) -> Dict[str, Any]:
        if quantity <= 0:
            return {"ok": False, "error": "Quantity must be positive"}
        if from_player_id == to_player_id:
            return {"ok": False, "error": "Cannot transfer to self"}

        first_id, second_id = sorted([from_player_id, to_player_id])
        async with self.player_locks[first_id]:
            async with self.player_locks[second_id]:
                from_player = self.players.get(from_player_id)
                to_player = self.players.get(to_player_id)
                if not from_player or not to_player:
                    return {"ok": False, "error": "Player not found"}

                item = self.items.get(item_id)
                if not item:
                    return {"ok": False, "error": "Item not found"}
                if item.owner_id != from_player_id:
                    return {"ok": False, "error": "Source player does not own item"}
                if item_id not in from_player.inventory:
                    return {"ok": False, "error": "Item missing from source inventory"}
                if not item.tradable:
                    return {"ok": False, "error": "Item is not tradable"}
                if item.quantity < quantity:
                    return {"ok": False, "error": "Insufficient quantity"}

                if item.quantity == quantity:
                    from_player.inventory.remove(item_id)
                    to_player.inventory.add(item_id)
                    item.owner_id = to_player_id
                    transferred_item_id = item_id
                    transferred_quantity = quantity
                else:
                    item.quantity -= quantity
                    new_item_id = str(uuid.uuid4())
                    new_item = Item(
                        id=new_item_id,
                        owner_id=to_player_id,
                        name=item.name,
                        quantity=quantity,
                        tradable=item.tradable,
                    )
                    self.items[new_item_id] = new_item
                    to_player.inventory.add(new_item_id)
                    transferred_item_id = new_item_id
                    transferred_quantity = quantity

                return {
                    "ok": True,
                    "item_id": transferred_item_id,
                    "from_player_id": from_player_id,
                    "to_player_id": to_player_id,
                    "quantity": transferred_quantity,
                }

    async def handle_trade(self, ws: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        from_player_id = self.connections.get(ws)
        if not from_player_id:
            await self.send(ws, {"type": "error", "message": "Not registered"})
            return

        to_player_id = data.get("to_player_id")
        item_id = data.get("item_id")
        quantity = int(data.get("quantity", 1))

        if not to_player_id or not item_id:
            await self.send(ws, {"type": "error", "message": "Missing to_player_id or item_id"})
            return

        result = await self.transfer_item(from_player_id, to_player_id, item_id, quantity)
        if not result["ok"]:
            await self.send(ws, {"type": "trade_result", "success": False, "error": result["error"]})
            return

        payload = {
            "type": "trade_result",
            "success": True,
            "item_id": result["item_id"],
            "from_player_id": result["from_player_id"],
            "to_player_id": result["to_player_id"],
            "quantity": result["quantity"],
        }

        await self.broadcast_to_players([from_player_id, to_player_id], payload)
        await self.broadcast_to_players(
            [from_player_id, to_player_id],
            {
                "type": "inventory_update",
                "players": {
                    from_player_id: await self.serialize_inventory(from_player_id),
                    to_player_id: await self.serialize_inventory(to_player_id),
                },
            },
        )

    async def handle_update_ownership(self, ws: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        requester_id = self.connections.get(ws)
        if not requester_id:
            await self.send(ws, {"type": "error", "message": "Not registered"})
            return

        item_id = data.get("item_id")
        new_owner_id = data.get("new_owner_id")
        quantity = int(data.get("quantity", 1))

        if not item_id or not new_owner_id:
            await self.send(ws, {"type": "error", "message": "Missing item_id or new_owner_id"})
            return

        result = await self.transfer_item(requester_id, new_owner_id, item_id, quantity)
        if not result["ok"]:
            await self.send(ws, {"type": "ownership_update_result", "success": False, "error": result["error"]})
            return

        await self.broadcast_to_players(
            [requester_id, new_owner_id],
            {
                "type": "ownership_update_result",
                "success": True,
                "item_id": result["item_id"],
                "previous_owner_id": requester_id,
                "new_owner_id": new_owner_id,
                "quantity": result["quantity"],
            },
        )
        await self.broadcast_to_players(
            [requester_id, new_owner_id],
            {
                "type": "inventory_update",
                "players": {
                    requester_id: await self.serialize_inventory(requester_id),
                    new_owner_id: await self.serialize_inventory(new_owner_id),
                },
            },
        )

    async def handle_create_item(self, ws: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        player_id = self.connections.get(ws)
        if not player_id:
            await self.send(ws, {"type": "error", "message": "Not registered"})
            return

        name = data.get("name", "UnnamedItem")
        quantity = int(data.get("quantity", 1))
        tradable = bool(data.get("tradable", True))
        if quantity <= 0:
            await self.send(ws, {"type": "error", "message": "Quantity must be positive"})
            return

        async with self.player_locks[player_id]:
            item_id = str(uuid.uuid4())
            item = Item(
                id=item_id,
                owner_id=player_id,
                name=name,
                quantity=quantity,
                tradable=tradable,
            )
            self.items[item_id] = item
            self.players[player_id].inventory.add(item_id)

        await self.send(
            ws,
            {
                "type": "item_created",
                "item": {
                    "id": item.id,
                    "owner_id": item.owner_id,
                    "name": item.name,
                    "quantity": item.quantity,
                    "tradable": item.tradable,
                },
            },
        )

    async def route_message(self, ws: WebSocketServerProtocol, raw_message: str) -> None:
        try:
            data = json.loads(raw_message)
        except json.JSONDecodeError:
            await self.send(ws, {"type": "error", "message": "Invalid JSON"})
            return

        action = data.get("action")
        if action == "register":
            await self.register_player(ws, data)
        elif action == "get_inventory":
            await self.handle_get_inventory(ws, data)
        elif action == "trade_item":
            await self.handle_trade(ws, data)
        elif action == "update_item_ownership":
            await self.handle_update_ownership(ws, data)
        elif action == "create_item":
            await self.handle_create_item(ws, data)
        else:
            await self.send(ws, {"type": "error", "message": f"Unknown action: {action}"})

    async def handler(self, ws: WebSocketServerProtocol) -> None:
        try:
            async for message in ws:
                await self.route_message(ws, message)
        except websockets.ConnectionClosed:
            pass
        finally:
            await self.unregister(ws)


async def main(host: str = "0.0.0.0", port: int = 8765) -> None:
    server = GameServer()
    stop = asyncio.Future()

    def request_shutdown() -> None:
        if not stop.done():
            stop.set_result(None)

    loop = asyncio.get_running_loop()
    for sig in (signal.SIGINT, signal.SIGTERM):
        try:
            loop.add_signal_handler(sig, request_shutdown)
        except NotImplementedError:
            pass

    async with websockets.serve(server.handler, host, port, max_size=2**20):
        logging.info("Game server started on %s:%s", host, port)
        await stop
        logging.info("Shutting down server")


if __name__ == "__main__":
    asyncio.run(main())